export interface Trailer {
  id: string;
  sku: string;
  name: string;
  category: TrailerCategory;
  price: number;
  salePrice?: number;
  description: string;
  specs: {
    gvwr: string;
    payload: string;
    axles: string;
    length: string;
    width: string;
  };
  features: string[];
  images: string[];
  status: 'In Stock' | 'Order Only' | 'Sold';
}

export enum TrailerCategory {
  UTILITY = 'Utility',
  DUMP = 'Dump',
  EQUIPMENT = 'Equipment',
  CARGO = 'Cargo',
  FLATBED = 'Flatbed/Gooseneck',
  LIVESTOCK = 'Livestock'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isThinking?: boolean;
}

export interface InventoryFilter {
  category: TrailerCategory | 'All';
  minPrice: number;
  maxPrice: number;
  search: string;
}

import { GoogleGenAI } from "@google/genai";
import { INVENTORY } from "../data/inventory";

// Initialize the API client
// Note: In a production environment, ensure your API key is restricted or use a backend proxy.
const apiKey = process.env.API_KEY || ''; 
const ai = new GoogleGenAI({ apiKey });

export const generateAssistantResponse = async (history: { role: string; parts: { text: string }[] }[], userMessage: string) => {
  if (!apiKey) {
    return "I'm sorry, I'm currently offline (API Key missing). Please call us at (281) 373-4905.";
  }

  // Create a context string based on current inventory
  const inventoryContext = INVENTORY.map(item => 
    `- ${item.name} (${item.sku}): ${item.category}, Price: $${item.price}, Specs: ${JSON.stringify(item.specs)}, Status: ${item.status}`
  ).join('\n');

  const systemInstruction = `
    You are "Tex", the intelligent sales assistant for Cypress Big Tex Trailers.
    Your goal is to help customers find the perfect trailer for their needs.

    You have access to the following LIVE INVENTORY:
    ${inventoryContext}

    GUIDELINES:
    1. Be helpful, rugged, and professional. Use a tone suitable for contractors and serious buyers.
    2. If a user asks for a trailer we have, recommend it by name and price.
    3. If they need something we don't have, suggest the closest alternative or suggest they call for a custom order.
    4. Ask clarifying questions if the user is vague (e.g., "What will you be hauling?" or "What is your truck's towing capacity?").
    5. Always emphasize "Big Tex" quality.
    6. Keep responses concise (under 100 words unless technical details are requested).
    7. If asked about financing, mention we work with Sheffield Financial and Clicklease.
  `;

  try {
    const model = ai.models.generateContent; // We will use direct generation for this simple implementation or chat.

    // Using chat-based model for context retention
    // Since we are in a stateless function call here effectively, we rebuild the chat.
    // In a real app, you'd keep the chat object alive. Here we simulate single turn with history context if we wanted, 
    // but for simplicity and robustness in this demo, we'll use generateContent with the full prompt stack or just a new Chat instance.

    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: systemInstruction,
      },
      history: history.map(h => ({
        role: h.role,
        parts: h.parts
      }))
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text;

  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having a little trouble connecting to the garage mainframe. Please try again or give us a call.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Sparkles, Loader2 } from 'lucide-react';
import { ChatMessage } from '../types';
import { generateAssistantResponse } from '../services/geminiService';

export const AIChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: "Howdy! I'm Tex, your virtual assistant. Looking for a specific trailer or need help with towing capacity? Ask away!",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Prepare history for API
    const history = messages.map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    try {
      const responseText = await generateAssistantResponse(history, userMsg.text);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText || "Sorry, I'm having trouble thinking right now.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-6 right-6 z-40 bg-brand-dark text-white p-4 rounded-full shadow-2xl hover:scale-110 transition-transform duration-300 group border-2 border-brand-red ${isOpen ? 'hidden' : 'flex'}`}
      >
        <MessageSquare className="w-6 h-6 group-hover:text-brand-red transition-colors" />
        <span className="absolute -top-2 -right-2 bg-brand-red text-xs font-bold w-5 h-5 flex items-center justify-center rounded-full animate-pulse">1</span>
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="fixed bottom-6 right-6 z-50 w-full max-w-sm bg-white rounded-xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col h-[500px] animate-fade-in-up">
          {/* Header */}
          <div className="bg-brand-dark p-4 flex justify-between items-center text-white">
            <div className="flex items-center">
              <div className="bg-brand-red p-2 rounded-lg mr-3">
                <Sparkles className="w-5 h-5 text-white" />
              </div>
              <div>
                <h3 className="font-bold font-display tracking-wide">TEX - AI ASSISTANT</h3>
                <p className="text-xs text-gray-400">Powered by Gemini</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white">
              <X className="w-6 h-6" />
            </button>
          </div>

          {/* Messages */}
          <div className="flex-grow overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[80%] rounded-2xl p-3 text-sm ${
                    msg.role === 'user'
                      ? 'bg-brand-red text-white rounded-tr-none'
                      : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm'
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-200 rounded-2xl rounded-tl-none p-3 shadow-sm flex items-center space-x-2">
                  <div className="w-2 h-2 bg-brand-red rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                  <div className="w-2 h-2 bg-brand-red rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                  <div className="w-2 h-2 bg-brand-red rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 bg-white border-t border-gray-100">
            <div className="flex items-center bg-gray-100 rounded-full px-4 py-2 border focus-within:border-brand-red focus-within:ring-1 focus-within:ring-brand-red transition-all">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Ask about trailers..."
                className="flex-grow bg-transparent outline-none text-sm text-gray-800 placeholder-gray-500"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isTyping}
                className="ml-2 text-brand-dark hover:text-brand-red disabled:opacity-50"
              >
                {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

import React from 'react';
import { TrailerCategory, InventoryFilter as IFilter } from '../types';

interface Props {
  filter: IFilter;
  setFilter: React.Dispatch<React.SetStateAction<IFilter>>;
}

export const InventoryFilter: React.FC<Props> = ({ filter, setFilter }) => {
  const categories = ['All', ...Object.values(TrailerCategory)];

  const handleCategoryChange = (cat: string) => {
    setFilter(prev => ({ ...prev, category: cat as TrailerCategory | 'All' }));
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-100 sticky top-24">
      <h3 className="font-display font-bold text-xl mb-6 border-b border-gray-100 pb-2">FILTER INVENTORY</h3>

      {/* Search */}
      <div className="mb-8">
        <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Keyword</label>
        <input 
          type="text" 
          placeholder="Search model, sku..." 
          value={filter.search}
          onChange={(e) => setFilter(prev => ({ ...prev, search: e.target.value }))}
          className="w-full bg-gray-50 border border-gray-200 rounded p-2 text-sm focus:border-brand-red focus:outline-none"
        />
      </div>

      {/* Categories */}
      <div className="mb-8">
        <label className="block text-xs font-bold text-gray-500 uppercase mb-3">Category</label>
        <div className="space-y-2">
          {categories.map(cat => (
            <label key={cat} className="flex items-center cursor-pointer group">
              <div className="relative flex items-center">
                <input 
                  type="radio" 
                  name="category"
                  checked={filter.category === cat}
                  onChange={() => handleCategoryChange(cat)}
                  className="peer h-4 w-4 opacity-0 absolute"
                />
                <div className={`w-4 h-4 border-2 rounded-full flex items-center justify-center transition-colors ${filter.category === cat ? 'border-brand-red' : 'border-gray-300 group-hover:border-gray-400'}`}>
                   {filter.category === cat && <div className="w-2 h-2 bg-brand-red rounded-full" />}
                </div>
              </div>
              <span className={`ml-3 text-sm ${filter.category === cat ? 'font-bold text-brand-dark' : 'text-gray-600'}`}>{cat}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Price Range (Simplified for demo) */}
      <div className="mb-6">
        <label className="block text-xs font-bold text-gray-500 uppercase mb-3">Price Range</label>
        <input 
          type="range" 
          min="0" 
          max="30000" 
          step="500"
          value={filter.maxPrice}
          onChange={(e) => setFilter(prev => ({ ...prev, maxPrice: parseInt(e.target.value) }))}
          className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-brand-red"
        />
        <div className="flex justify-between text-xs text-gray-500 mt-2 font-mono">
          <span>$0</span>
          <span>${filter.maxPrice.toLocaleString()}</span>
        </div>
      </div>

      <button 
        onClick={() => setFilter({ category: 'All', minPrice: 0, maxPrice: 50000, search: '' })}
        className="w-full py-2 text-xs font-bold text-gray-500 border border-gray-200 hover:bg-gray-50 hover:text-brand-red transition-colors"
      >
        RESET FILTERS
      </button>
    </div>
  );
};

