import { GoogleGenAI } from "@google/genai";
import { Trailer } from "../types";

// Initialize the API client
// Note: In a production environment, ensure your API key is restricted or use a backend proxy.
const apiKey = process.env.API_KEY || ''; 
const ai = new GoogleGenAI({ apiKey });

export const generateAssistantResponse = async (
  history: { role: string; parts: { text: string }[] }[], 
  userMessage: string,
  currentInventory: Trailer[]
) => {
  if (!apiKey) {
    return "I'm sorry, I'm currently offline (API Key missing). Please call us at (281) 373-4905.";
  }

  // Create a context string based on CURRENT (Dynamic) inventory
  const inventoryContext = currentInventory.map(item => 
    `- ${item.name} (${item.sku}): ${item.category}, Price: $${item.price}, Status: ${item.status}`
  ).join('\n');

  const systemInstruction = `
    You are "Tex", the intelligent sales assistant for Cypress Big Tex Trailers.
    Your goal is to help customers find the perfect trailer for their needs.

    You have access to the following LIVE INVENTORY (Real-time data):
    ${inventoryContext}

    GUIDELINES:
    1. Be helpful, rugged, and professional. Use a tone suitable for contractors and serious buyers.
    2. If a user asks for a trailer we have, recommend it by name and price.
    3. If they need something we don't have, suggest the closest alternative or suggest they call for a custom order.
    4. Ask clarifying questions if the user is vague (e.g., "What will you be hauling?" or "What is your truck's towing capacity?").
    5. Always emphasize "Big Tex" quality.
    6. Keep responses concise (under 100 words unless technical details are requested).
    7. If asked about financing, mention we work with Sheffield Financial and Clicklease.
  `;

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: systemInstruction,
      },
      history: history.map(h => ({
        role: h.role,
        parts: h.parts
      }))
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text;

  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having a little trouble connecting to the garage mainframe. Please try again or give us a call.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Sparkles, Loader2 } from 'lucide-react';
import { ChatMessage } from '../types';
import { generateAssistantResponse } from '../services/geminiService';
import { useInventory } from '../context/InventoryContext';

export const AIChat: React.FC = () => {
  const { inventory } = useInventory(); // Get real-time inventory
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: "Howdy! I'm Tex, your virtual assistant. Looking for a specific trailer or need help with towing capacity? Ask away!",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Prepare history for API
    const history = messages.map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    try {
      // Pass the current inventory from context to the service
      const responseText = await generateAssistantResponse(history, userMsg.text, inventory);

      const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText || "Sorry, I'm having trouble thinking right now.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-6 right-6 z-40 bg-brand-dark text-white p-4 rounded-full shadow-2xl hover:scale-110 transition-transform duration-300 group border-2 border-brand-red ${isOpen ? 'hidden' : 'flex'}`}
      >
        <MessageSquare className="w-6 h-6 group-hover:text-brand-red transition-colors" />
        <span className="absolute -top-2 -right-2 bg-brand-red text-xs font-bold w-5 h-5 flex items-center justify-center rounded-full animate-pulse">1</span>
      </button>

      {/* Chat Window */}
      {isOpen && (
        <div className="fixed bottom-6 right-6 z-50 w-full max-w-sm bg-white rounded-xl shadow-2xl border border-gray-200 overflow-hidden flex flex-col h-[500px] animate-fade-in-up">
          {/* Header */}
          <div className="bg-brand-dark p-4 flex justify-between items-center text-white">
            <div className="flex items-center">
              <div className="bg-brand-red p-2 rounded-lg mr-3">
                <Sparkles className="w-5 h-5 text-white" />
              </div>
              <div>
                <h3 className="font-bold font-display tracking-wide">TEX - AI ASSISTANT</h3>
                <p className="text-xs text-gray-400">Powered by Gemini</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white">
              <X className="w-6 h-6" />
            </button>
          </div>

          {/* Messages */}
          <div className="flex-grow overflow-y-auto p-4 space-y-4 bg-gray-50">
            {messages.map((msg) => (
              <div
                key={msg.id}
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`max-w-[80%] rounded-2xl p-3 text-sm ${
                    msg.role === 'user'
                      ? 'bg-brand-red text-white rounded-tr-none'
                      : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm'
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-200 rounded-2xl rounded-tl-none p-3 shadow-sm flex items-center space-x-2">
                  <div className="w-2 h-2 bg-brand-red rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                  <div className="w-2 h-2 bg-brand-red rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                  <div className="w-2 h-2 bg-brand-red rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-4 bg-white border-t border-gray-100">
            <div className="flex items-center bg-gray-100 rounded-full px-4 py-2 border focus-within:border-brand-red focus-within:ring-1 focus-within:ring-brand-red transition-all">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyPress}
                placeholder="Ask about trailers..."
                className="flex-grow bg-transparent outline-none text-sm text-gray-800 placeholder-gray-500"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isTyping}
                className="ml-2 text-brand-dark hover:text-brand-red disabled:opacity-50"
              >
                {isTyping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

