              <p className="mb-6 max-w-sm mx-auto">Your lot is empty. Click the "Add Trailer" button above to start stocking up.</p>
              <button onClick={() => setIsAddModalOpen(true)} className="text-brand-red font-bold hover:underline">Add Your First Trailer</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export interface Trailer {
  id: string;
  sku: string;
  name: string;
  brand: string; // New field
  category: TrailerCategory;
  price: number;
  salePrice?: number;
  description: string;
  specs: {
    gvwr: string;
    payload: string;
    axles: string;
    length: string;
    width: string;
  };
  features: string[];
  images: string[];
  status: 'In Stock' | 'Order Only' | 'Sold';
  isFeatured?: boolean;
}

