  UTILITY = 'Utility',
  DUMP = 'Dump',
  EQUIPMENT = 'Equipment',
  CARGO = 'Cargo',
  FLATBED = 'Flatbed/Gooseneck',
  LIVESTOCK = 'Livestock'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isThinking?: boolean;
}

export interface InventoryFilter {
  category: TrailerCategory | 'All';
  brand: string | 'All'; // New filter
  minPrice: number;
  maxPrice: number;
  search: string;
}

